import { useState } from "react";
import Card from "../components/Card";

export default function TasksPage() {
  const domain = localStorage.getItem("selectedDomain");
  const currentDay = parseInt(localStorage.getItem("currentDay") || "1");
  const timeline = localStorage.getItem("timeline") || "3 months";
  const totalDays = parseInt(timeline) * 30;

  const topicMap = {
    "ai-and-ml": [
      ["Python Basics", "Variables"],
      ["Loops", "Conditions"],
      ["Functions"],
      ["NumPy"],
      ["Pandas"],
      ["Visualization"],
      ["ML Algorithms"],
      ["Deep Learning"],
      ["Project"]
    ]
  };

  const topics = topicMap[domain] || [["Basics"]];

  const getTasksForDay = (day) => {
    const index = Math.floor((day / totalDays) * topics.length);
    const newTasks = topics[index] || [];

    const carry = JSON.parse(localStorage.getItem("carryForward") || "[]");

    return [...carry, ...newTasks];
  };

  const todayTasks = getTasksForDay(currentDay);

  const [completed, setCompleted] = useState([]);

  const toggleTask = (task) => {
    if (completed.includes(task)) {
      setCompleted(completed.filter(t => t !== task));
    } else {
      setCompleted([...completed, task]);
    }
  };

  const handleSave = () => {
    const remaining = todayTasks.filter(task => !completed.includes(task));

    localStorage.setItem("carryForward", JSON.stringify(remaining));
    localStorage.setItem("currentDay", currentDay + 1);

    alert("Progress saved!");
  };

  return (
    <div className="space-y-8">
      <Card title={`Day ${currentDay} Tasks`}>

        {todayTasks.map((task, i) => (
          <div key={i} className="flex gap-3 items-center">
            <input type="checkbox" onChange={() => toggleTask(task)} />
            <span>{task}</span>
          </div>
        ))}

        <button
          onClick={handleSave}
          className="mt-4 px-4 py-2 bg-teal-500 text-white rounded-lg"
        >
          Save Progress
        </button>

      </Card>
    </div>
  );
}
